function UIShop:shopFitnessEquipUpdate(data)
    local builder = json.decode(data)
    for _, Value in pairs(builder) do
        local temp = FitnessEquipConfig:getFitnessEquipById(Value.Id)
        if temp then
            temp.Status = Value.Status
        end
        --LogUtil.log("UIShop:shopFitnessEquipUpdate " .. inspect.inspect(temp))
    end

    if self.selectTab == TabKind.FitnessEquip then
        self:addItemsGridView(false)
        self:onClickFitnessEquipItem(self.selectItemId)
    end
end

function UIShop:shopGeneUpdate(data)
    local builder = json.decode(data)
    for _, Value in pairs(builder) do
        local temp = GeneConfig:getGeneById(Value.Id)
        if temp then
            temp.Status = Value.Status
        end
    end

    if self.selectTab == TabKind.Gene then
        self:addItemsGridView(false)
        self:onClickGeneItem(self.selectItemId)
    end
end

function UIShop:shopAdvancedUpdate(data)
    local builder = json.decode(data)
    for _, Value in pairs(builder) do
        local temp = AdvancedConfig:getAdvancedById(Value.Id)
