function UIShop:addView(kind, Value, ItemIcon, index)
    local shopItem = GUIShopItem.new("LiftingSimulatorShopItem.json")

    ItemIcon = Value.Icon

    shopItem:initItem(kind, Value, ItemIcon)

    local contentWidth = self.gvContentItemsGridView:getWidth()
    local contentHeight = self.gvContentItemsGridView:getHeight()
    local itemWidth = (contentWidth - 30) / 4
    local itemHeight = (contentHeight - 20) / 3

    shopItem:setArea({ 0, 0 }, { 0, 0 }, { 0, itemWidth }, { 0, itemHeight })
    self.gvContentItemsGridView:addItemByIndex(shopItem, index)

    return shopItem
end

function UIShop:addFitnessEquipView(flag)
    local i = 1

    table.sort(FitnessEquipConfig:getFitnessEquips(), function(a, b)
        return a.sortId < b.sortId
    end)

    local skipNum = 0
    for _, Value in pairs(FitnessEquipConfig:getFitnessEquips()) do
        local ItemIcon = "set:LiftingSimulatorShop1.json image:equipOrSkillBg"
        if (i + skipNum) % 4 == 0 and Value.payConfigId == 0 then
            local shopItem = self:addView(TabKind.FitnessEquip, Value, ItemIcon)
            shopItem:hideGUIWindow()
            skipNum = skipNum + 1
        end
        self.itemsGridView[i] = self:addView(TabKind.FitnessEquip, Value, ItemIcon)
        i = i + 1
    end

    if flag and #self.itemsGridView >= 1 then
        self:resetPosFitnessEquip()
    end
end

function UIShop:resetPosFitnessEquip()

    table.sort(FitnessEquipConfig:getFitnessEquips(), function(a, b)
        return a.sortId < b.sortId
    end)

    local i = 0
    local flag = false
    local itemId = -1
    for _, Value in pairs(FitnessEquipConfig:getFitnessEquips()) do

        --print("---------"..Value.Id.."-----------")
        i = i + 1
        if Value.Status == ItemBuyStatus.Used then
            itemId = Value.Id
            flag = true
            break
        end
    end

    if flag == false then
        i = 1 
        itemId = self.itemsGridView[1].itemId
        flag = true
    end

    if flag then
        local height = 153.66*(math.floor((i-1)/4))+10*(math.floor((i-1)/4))
        self.gvContentItemsGridView.root:ResetPos1(-height)
        self:onClickFitnessEquipItem(itemId)
    end

end

