function UIShop:addAdvancedView(flag)
    local i = 1
    table.sort(AdvancedConfig:getAdvanceds(), function(a, b)
        --if a.Status ~= b.Status then
        --    return a.Status > b.Status
        --end
        return a.Id < b.Id
    end)
    for _, Value in pairs(AdvancedConfig:getAdvanceds()) do
        --local shopItem = GUIShopItem.new("LiftingSimulatorShopItem.json")
        local ItemIcon = "set:LiftingSimulatorShop1.json image:advancedBg"
        self.itemsGridView[i] = self:addView(TabKind.Advanced, Value, ItemIcon)
        --加图集
        i = i + 1
    end
    if flag and #self.itemsGridView >= 1 then
        self:onClickAdvanceItem(self.itemsGridView[1].itemId)
        self.gvContentItemsGridView.root:ResetPos(0)
    end
end

function UIShop:addSkillView(flag)

    local i = 1

    table.sort(SkillConfig:getSkills(), function(a, b)
        if a.Status ~= b.Status then
            return a.Status > b.Status
        end
        return a.Id < b.Id
    end)

    for _, Value in pairs(SkillConfig:getSkills()) do
        --local shopItem = GUIShopItem.new("LiftingSimulatorShopItem.json")
        local ItemIcon = "set:LiftingSimulatorShop1.json image:equipOrSkillBg"
        self.itemsGridView[i] = self:addView(TabKind.Skill, Value, ItemIcon)
        i = i + 1
    end
    if flag and #self.itemsGridView >= 1 then
        self:onClickSkillItem(self.itemsGridView[1].itemId)
        self.gvContentItemsGridView.root:ResetPos(0)
    end
end

--点击Tab
function UIShop:onClickTab(Id, Type)

    --print("---------onClickTab-----------")
    for _, shopTab in pairs(self.tabList) do
        if shopTab.tabId ~= Id then

            --加图集
            local strBg = "set:LiftingSimulatorShop1.json image:tabBg1"
            shopTab:changeSelectStatus(strBg, TabSelectStatus.NotSelect)

        else
            --加图集
            local strBg = "set:LiftingSimulatorShop1.json image:tabBg2"
            shopTab:changeSelectStatus(strBg, TabSelectStatus.Select)
            --self.selectTab = shopTab.kind
        end
    end

    if self.selectTab ~= Type then
        self.selectTab = Type
        self:addItemsGridView(true)
    end

end

function UIShop:selectItem(itemId)
    for _, shopItem in pairs(self.itemsGridView) do
        if shopItem.itemId ~= itemId then

            --加图集
            local strBg = "set:LiftingSimulatorShop1.json image:ItemBg2"

            if shopItem.kind == TabKind.FitnessEquip or shopItem.kind == TabKind.Gene then
                if self:isShowCostPanel(shopItem.moneyType, shopItem.itemId) then
                    strBg = "set:LiftingSimulatorShop1.json image:costBg3"
                end
            end

            shopItem:changeSelectStatus(strBg, TabSelectStatus.NotSelect)

        else
            --加图集
            local strBg = "set:LiftingSimulatorShop1.json image:itemBg1"

            if shopItem.kind == TabKind.FitnessEquip or shopItem.kind == TabKind.Gene then
                if self:isShowCostPanel(shopItem.moneyType, shopItem.itemId) then
                    strBg = "set:LiftingSimulatorShop1.json image:costBg4"
                end
            end
            shopItem:changeSelectStatus(strBg, TabSelectStatus.Select)
        end

    end
end

