function UIShop:onButtonExit()
    self:hide()
end

function UIShop:showShop()
    self:show()

    self:onClickTab(TabKind.FitnessEquip, TabKind.FitnessEquip)

    if self.selectTab == TabKind.FitnessEquip then
        self:resetPosFitnessEquip()
    end
end

function UIShop:onToolBarGoldClick()
    self:show()
end

function UIShop:onShopRegion(data)
    --print("shopRegion")
    --print(data)
    local builder = DataBuilder.new():fromData(data)
    local isVisible = builder:getBoolParam("ShopStatus")
    if isVisible then
        self:show()
        if self.selectTab == TabKind.FitnessEquip then
            self:resetPosFitnessEquip()
        end

        if self.selectTab == TabKind.Gene then
            self:resetPosGene()
        end
    else
        self:hide()
    end

end

function UIShop:onFitnessEquipButton()

    local oneFitnessEquip = FitnessEquipConfig:getFitnessEquipById(self.selectItemId)

    if oneFitnessEquip == nil then
        return
    end

    if oneFitnessEquip.Status == ItemBuyStatus.Unlock and
            (oneFitnessEquip.MoneyType == Define.MoneyType.DiamondGolds1 or oneFitnessEquip.MoneyType == Define.MoneyType.DiamondGolds2) then
        PayHelper.checkMoney(MoneyType.Diamonds, oneFitnessEquip.Price, function(isEnough)
            if isEnough then
                --print("onFitnessEquipButton()")
                self:senderDetailButtonClick()
            end
        end)
    elseif oneFitnessEquip.Status == ItemBuyStatus.Unlock and oneFitnessEquip.MoneyType == Define.MoneyType.SLGolds
            and GUIMainControl.goldNum < oneFitnessEquip.Price then

        local listener = function()
            LuaTimer:schedule(function()
                GUIMainControl:onClickWorkout()
            end, 1)
        end

        CustomDialog.builder()
                    .setContentText(Lang:getString("gold_enough"))
                    .setRightClickListener(listener)
                    .show()

    else
        self:senderDetailButtonClick()
    end

end

function UIShop:onGeneButton()

    local gene = GeneConfig:getGeneById(self.selectItemId)

    if gene == nil then
        return
    end

    if gene.Status == ItemBuyStatus.Unlock and
            (gene.MoneyType == Define.MoneyType.DiamondGolds1 or gene.MoneyType == Define.MoneyType.DiamondGolds2) then
        PayHelper.checkMoney(MoneyType.Diamonds, gene.Price, function(isEnough)
