    end

end

function UIShop:onAdvanceButton()

    local advanced = AdvancedConfig:getAdvancedById(self.selectItemId)

    if advanced == nil then
        return
    end

    if advanced.Status == ItemBuyStatus.Buy then

        local listener = function()
            self:senderDetailButtonClick()
            self:hide()
        end
        CustomDialog.builder()
                    .setContentText(Lang:getString(advanced.Tips))
                    .setRightClickListener(listener)
                    .show()

        return
    end

    if advanced.Status == ItemBuyStatus.Unlock and
            (advanced.MoneyType == Define.MoneyType.DiamondGolds1 or advanced.MoneyType == Define.MoneyType.DiamondGolds2) then
        PayHelper.checkMoney(MoneyType.Diamonds, advanced.Price, function(isEnough)
            if isEnough then
                --print("onAdvanceButton()")
                self:senderDetailButtonClick()
            end
        end)
    else
        self:senderDetailButtonClick()
    end
end

