function UIShop:senderDetailButtonClick()
    local data = {
        Kind = self.selectTab,
        ItemId = self.selectItemId
    }
    local builder = DataBuilder.new():fromTable(data):getData()
    PacketSender:sendLuaCommonData("ShopButtonClick", builder)
end

--购买、使用逻辑
function UIShop:onDetailButton()
    if self.selectTab == TabKind.FitnessEquip then
        self:onFitnessEquipButton()
    end
    if self.selectTab == TabKind.Gene then
        self:onGeneButton()
    end
    if self.selectTab == TabKind.Advanced then
        self:onAdvanceButton()
    end
    if self.selectTab == TabKind.Skill then
        self:onSkillButton()
    end
end

function UIShop:onShopItemSelectStatus(data)

    local builder = DataBuilder.new():fromData(data)

    local selectTable = builder:getNumberParam("selectTable")
    local selectItemId = builder:getNumberParam("selectItemId")

    if selectTable == TabKind.FitnessEquip then
        self:onClickFitnessEquipItem(selectItemId)
    end
    if selectTable == TabKind.Gene then
        self:onClickGeneItem(selectItemId)
    end
    if selectTable == TabKind.Advanced then
        self:onClickAdvanceItem(selectItemId)
    end
    if selectTable == TabKind.Skill then
        self:onClickSkillItem(selectItemId)
    end

end

function UIShop:onRefreshPayFitnessEquipItem()

    if self.selectTab == TabKind.FitnessEquip then
        local oneFitnessEquip = FitnessEquipConfig:getFitnessEquipById(self.selectItemId)
        if oneFitnessEquip == nil then
            return
        end
        local payFitnessEquip = PayFitnessEquipConfig:getPayFitnessEquipConfig(oneFitnessEquip.payConfigId)
        if (oneFitnessEquip.MoneyType == Define.MoneyType.DiamondGolds1 or oneFitnessEquip.MoneyType == Define.MoneyType.DiamondGolds2)
                and payFitnessEquip then
            self:onClickFitnessEquipItem(self.selectItemId)
        end
    end
end

function UIShop:isShowCostPanel(monryType, itemId)
    if (monryType == Define.MoneyType.DiamondGolds1 or monryType == Define.MoneyType.DiamondGolds2) and itemId ~= 208 and itemId ~= 111 then
        return true
    end
    return false
end


function UIShop:itemNotShowBigNumMoney(monryType)
    if (monryType == Define.MoneyType.DiamondGolds1 or monryType == Define.MoneyType.DiamondGolds2) then
        return true
    end
    return false
end

return UIShop